<script lang="ts">
	import { createEventDispatcher } from 'svelte';

	const dispatch = createEventDispatcher();

	type WorkspaceNode = {
		id: string;
		workspace_id: string;
		parent_id: string | null;
		node_type: 'file' | 'directory';
		name: string;
		path: string;
		content: string;
		mime_type: string;
		size_bytes: number;
	};

	export let node: WorkspaceNode;
	export let nodes: WorkspaceNode[];
	export let expandedDirs: string[];
	export let renameNodeId: string | null;
	export let renameValue: string;
	export let editingNodeId: string | null;
	export let depth: number = 0;

	$: isExpanded = expandedDirs.includes(node.id);
	$: children = nodes
		.filter((n) => n.parent_id === node.id)
		.sort((a, b) => {
			if (a.node_type !== b.node_type) return a.node_type === 'directory' ? -1 : 1;
			return a.name.localeCompare(b.name);
		});
</script>

<div style="padding-left: {depth * 12}px">
	<div
		class="group flex items-center gap-1 rounded px-1.5 py-0.5 cursor-pointer hover:bg-gray-100 dark:hover:bg-gray-800 {editingNodeId === node.id ? 'bg-blue-50 dark:bg-blue-900/20' : ''}"
		role="button"
		tabindex="0"
		draggable={true}
		on:click={() => {
			if (node.node_type === 'directory') dispatch('toggle', node.id);
			else dispatch('open-editor', node);
		}}
		on:dragstart={() => dispatch('drag-start', node.id)}
		on:dragend={() => dispatch('drag-end')}
		on:dragover={(e) => {
			if (node.node_type === 'directory') {
				e.preventDefault();
			}
		}}
		on:drop={(e) => {
			if (node.node_type === 'directory') {
				e.preventDefault();
				dispatch('drop-on-dir', node.id);
			}
		}}
		on:keydown={(e) => {
			if (e.key === 'Enter') {
				if (node.node_type === 'directory') dispatch('toggle', node.id);
				else dispatch('open-editor', node);
			}
		}}
	>
		<!-- Icon -->
		{#if node.node_type === 'directory'}
			<svg xmlns="http://www.w3.org/2000/svg" class="h-3.5 w-3.5 shrink-0 text-yellow-500" fill="currentColor" viewBox="0 0 20 20">
				{#if isExpanded}
					<path d="M2 6a2 2 0 012-2h4l2 2h6a2 2 0 012 2v6a2 2 0 01-2 2H4a2 2 0 01-2-2V6z" />
				{:else}
					<path fill-rule="evenodd" d="M2 6a2 2 0 012-2h4l2 2h6a2 2 0 012 2v6a2 2 0 01-2 2H4a2 2 0 01-2-2V6z" clip-rule="evenodd" />
				{/if}
			</svg>
		{:else}
			<svg xmlns="http://www.w3.org/2000/svg" class="h-3.5 w-3.5 shrink-0 text-gray-400" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="1.5">
				<path stroke-linecap="round" stroke-linejoin="round" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414A1 1 0 0121 9.414V19a2 2 0 01-2 2z" />
			</svg>
		{/if}

		<!-- Name / rename input -->
		{#if renameNodeId === node.id}
			<input
				class="flex-1 min-w-0 rounded border border-blue-400 bg-white dark:bg-gray-800 px-1 text-xs focus:outline-none"
				value={renameValue}
				autofocus
				on:input={(e) => dispatch('rename-input', e.currentTarget.value)}
				on:blur={() => dispatch('rename-commit', node)}
				on:keydown={(e) => {
					if (e.key === 'Enter') dispatch('rename-commit', node);
					if (e.key === 'Escape') dispatch('rename-commit', { ...node, name: node.name });
				}}
				on:click|stopPropagation
			/>
		{:else}
			<span class="flex-1 truncate text-xs text-gray-700 dark:text-gray-300">{node.name}</span>
		{/if}

		<!-- Actions -->
		<div class="invisible group-hover:visible flex items-center gap-0.5 ml-auto shrink-0">
			{#if node.node_type === 'directory'}
				<button
					class="rounded p-0.5 text-gray-400 hover:text-gray-600 dark:hover:text-gray-200"
					title="New file here"
					on:click|stopPropagation={() => dispatch('create-file', node.id)}
				>
					<svg xmlns="http://www.w3.org/2000/svg" class="h-3 w-3" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2">
						<path stroke-linecap="round" stroke-linejoin="round" d="M12 4v16m8-8H4" />
					</svg>
				</button>
				<button
					class="rounded p-0.5 text-gray-400 hover:text-gray-600 dark:hover:text-gray-200"
					title="New folder here"
					on:click|stopPropagation={() => dispatch('create-dir', node.id)}
				>
					<svg xmlns="http://www.w3.org/2000/svg" class="h-3 w-3" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2">
						<path stroke-linecap="round" stroke-linejoin="round" d="M3 7a2 2 0 012-2h4l2 2h8a2 2 0 012 2v8a2 2 0 01-2 2H5a2 2 0 01-2-2V7z" />
					</svg>
				</button>
			{/if}
			<button
				class="rounded p-0.5 text-gray-400 hover:text-gray-600 dark:hover:text-gray-200"
				title="Rename"
				on:click|stopPropagation={() => dispatch('rename-start', node)}
			>
				<svg xmlns="http://www.w3.org/2000/svg" class="h-3 w-3" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2">
					<path stroke-linecap="round" stroke-linejoin="round" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" />
				</svg>
			</button>
			<button
				class="rounded p-0.5 text-gray-400 hover:text-red-500"
				title="Delete"
				on:click|stopPropagation={() => dispatch('delete', node)}
			>
				<svg xmlns="http://www.w3.org/2000/svg" class="h-3 w-3" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2">
					<path stroke-linecap="round" stroke-linejoin="round" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
				</svg>
			</button>
		</div>
	</div>

	<!-- Children -->
	{#if node.node_type === 'directory' && isExpanded}
		{#each children as child (child.id)}
			<svelte:self
				node={child}
				{nodes}
				{expandedDirs}
				{renameNodeId}
				{renameValue}
				{editingNodeId}
				depth={depth + 1}
				on:toggle
				on:rename-start
				on:rename-input
				on:rename-commit
				on:delete
				on:open-editor
				on:create-file
				on:create-dir
				on:drag-start
				on:drag-end
				on:drop-on-dir
			/>
		{/each}
	{/if}
</div>
