<script lang="ts">
	import { onMount } from 'svelte';
	import { browser } from '$app/environment';
	import { toast } from 'svelte-sonner';
	import { user, models } from '$lib/stores';
	import {
		listWorkspaces,
		createWorkspace,
		deleteWorkspace,
		listWorkspaceNodes,
		createWorkspaceNode,
		updateWorkspaceNode,
		deleteWorkspaceNode,
		runWorkspaceAgent,
		getWorkspaceAgentStatus,
		downloadWorkspaceArchive,
		downloadWorkspaceNode
	} from '$lib/apis/gpthub';
	import CodeEditor from '$lib/components/common/CodeEditor.svelte';
	import Markdown from '$lib/components/chat/Messages/Markdown.svelte';

	import WorkspaceTreeNode from './WorkspaceTreeNode.svelte';

	type WorkspaceNode = {
		id: string;
		workspace_id: string;
		parent_id: string | null;
		node_type: 'file' | 'directory';
		name: string;
		path: string;
		content: string;
		mime_type: string;
		size_bytes: number;
	};

	type Workspace = {
		id: string;
		owner_id: string;
		name: string;
		description: string;
	};

	type AIChatMessage = {
		id: string;
		role: 'user' | 'assistant' | 'system';
		content: string;
	};

	let token: string = '';

	let showWorkspaceList = true;
	let workspaces: Workspace[] = [];
	let activeWorkspace: Workspace | null = null;
	let nodes: WorkspaceNode[] = [];

	let newWorkspaceName = '';
	let showNewWorkspace = false;
	let showCreateNodeForm = false;
	let createNodeName = '';
	let createNodeType: 'file' | 'directory' = 'file';
	let createNodeParentId: string | null = null;

	let renameNodeId: string | null = null;
	let renameValue = '';

	let editingNodeId: string | null = null;
	let editingContent = '';

	let expandedDirs: string[] = [];
	let rootNodes: WorkspaceNode[] = [];
	let fileInputEl: HTMLInputElement | null = null;
	let folderInputEl: HTMLInputElement | null = null;
	let isUploading = false;
	let isDownloadingWorkspace = false;
	let draggingNodeId: string | null = null;

	let aiMessages: AIChatMessage[] = [];
	let aiInput = '';
	let aiLoading = false;
	let aiLoadingStatus = '';
	let aiUseAutopilot = true;
	let showAiOptions = false;

	$: ownerId = $user?.id ?? '';

	let _initializedOwnerId = '';
	$: if (browser && ownerId && _initializedOwnerId !== ownerId) {
		_initializedOwnerId = ownerId;
		token = localStorage.token ?? '';
		void loadWorkspaces();
	}

	function workspaceChatStorageKey(workspaceId: string): string {
		return `workspace-agent-history:${workspaceId}`;
	}

	function loadWorkspaceChatHistory(workspaceId: string): AIChatMessage[] {
		if (!browser) return [];
		try {
			const raw = localStorage.getItem(workspaceChatStorageKey(workspaceId));
			if (!raw) return [];
			const parsed = JSON.parse(raw);
			if (!Array.isArray(parsed)) return [];
			return parsed
				.filter(
					(item) =>
						item &&
						typeof item.id === 'string' &&
						(item.role === 'user' || item.role === 'assistant' || item.role === 'system') &&
						typeof item.content === 'string'
				)
				.slice(-80);
		} catch {
			return [];
		}
	}

	function persistWorkspaceChatHistory(workspaceId: string, messages: AIChatMessage[]) {
		if (!browser) return;
		localStorage.setItem(
			workspaceChatStorageKey(workspaceId),
			JSON.stringify(messages.slice(-80))
		);
	}

	onMount(() => {
		if (folderInputEl) {
			folderInputEl.setAttribute('webkitdirectory', '');
			folderInputEl.setAttribute('directory', '');
		}
	});

	$: rootNodes = nodes
		.filter((n) => n.parent_id === null)
		.sort((a, b) => {
			if (a.node_type !== b.node_type) return a.node_type === 'directory' ? -1 : 1;
			return a.name.localeCompare(b.name);
		});

	async function loadWorkspaces() {
		if (!ownerId) return;
		try {
			workspaces = await listWorkspaces(token, ownerId);
			if (workspaces.length > 0 && !activeWorkspace) {
				await selectWorkspace(workspaces[0]);
			}
		} catch (e: any) {
			toast.error(e?.message ?? 'Failed to load workspaces');
		}
	}

	async function selectWorkspace(ws: Workspace) {
		activeWorkspace = ws;
		showWorkspaceList = false;
		aiMessages = loadWorkspaceChatHistory(ws.id);
		editingNodeId = null;
		await loadNodes();
	}

	function leaveWorkspace() {
		activeWorkspace = null;
		nodes = [];
		aiMessages = [];
		editingNodeId = null;
		showWorkspaceList = true;
	}

	async function loadNodes() {
		if (!activeWorkspace) return;
		try {
			nodes = await listWorkspaceNodes(token, ownerId, activeWorkspace.id);
		} catch (e: any) {
			toast.error(e?.message ?? 'Failed to load nodes');
		}
	}

	async function handleCreateWorkspace() {
		if (!newWorkspaceName.trim()) return;
		try {
			const ws = await createWorkspace(token, ownerId, { name: newWorkspaceName.trim() });
			workspaces = [...workspaces, ws];
			newWorkspaceName = '';
			showNewWorkspace = false;
			await selectWorkspace(ws);
		} catch (e: any) {
			toast.error(e?.message ?? 'Failed to create workspace');
		}
	}

	async function handleDeleteWorkspace(ws: Workspace) {
		if (!confirm(`Delete workspace "${ws.name}"?`)) return;
		try {
			await deleteWorkspace(token, ownerId, ws.id);
			if (browser) {
				localStorage.removeItem(workspaceChatStorageKey(ws.id));
			}
			workspaces = workspaces.filter((w) => w.id !== ws.id);
			if (activeWorkspace?.id === ws.id) {
				activeWorkspace = workspaces[0] ?? null;
				nodes = [];
				if (activeWorkspace) {
					await loadNodes();
				} else {
					showWorkspaceList = true;
				}
			}
		} catch (e: any) {
			toast.error(e?.message ?? 'Failed to delete workspace');
		}
	}

	async function handleCreateNode(parentId: string | null, nodeType: 'file' | 'directory') {
		createNodeParentId = parentId;
		createNodeType = nodeType;
		createNodeName = '';
		showCreateNodeForm = true;
	}

	async function handleSubmitCreateNodeForm() {
		if (!activeWorkspace || !createNodeName.trim()) return;
		try {
			await createWorkspaceNode(token, ownerId, activeWorkspace.id, {
				name: createNodeName.trim(),
				node_type: createNodeType,
				parent_id: createNodeParentId
			});
			await loadNodes();
			if (createNodeParentId && !expandedDirs.includes(createNodeParentId)) {
				expandedDirs = [...expandedDirs, createNodeParentId];
			}
			createNodeName = '';
			createNodeParentId = null;
			showCreateNodeForm = false;
		} catch (e: any) {
			toast.error(e?.message ?? 'Failed to create node');
		}
	}

	async function handleRenameNode(node: WorkspaceNode) {
		if (!activeWorkspace || renameValue.trim() === '' || renameValue === node.name) {
			renameNodeId = null;
			return;
		}
		try {
			await updateWorkspaceNode(token, ownerId, activeWorkspace.id, node.id, {
				name: renameValue.trim()
			});
			await loadNodes();
		} catch (e: any) {
			toast.error(e?.message ?? 'Failed to rename');
		} finally {
			renameNodeId = null;
		}
	}

	async function handleDeleteNode(node: WorkspaceNode) {
		if (!activeWorkspace) return;
		if (!confirm(`Delete "${node.name}"?`)) return;
		try {
			await deleteWorkspaceNode(token, ownerId, activeWorkspace.id, node.id);
			await loadNodes();
			if (editingNodeId === node.id) editingNodeId = null;
		} catch (e: any) {
			toast.error(e?.message ?? 'Failed to delete node');
		}
	}

	async function handleSaveContent(node: WorkspaceNode) {
		if (!activeWorkspace) return;
		try {
			await updateWorkspaceNode(token, ownerId, activeWorkspace.id, node.id, {
				content: editingContent
			});
			await loadNodes();
			toast.success('Saved');
		} catch (e: any) {
			toast.error(e?.message ?? 'Failed to save');
		} finally {
			editingNodeId = null;
		}
	}

	function handleDragStart(nodeId: string) {
		draggingNodeId = nodeId;
	}

	function handleDragEnd() {
		draggingNodeId = null;
	}

	async function handleDropToParent(targetParentId: string | null) {
		if (!activeWorkspace || !draggingNodeId) return;
		const movingNode = nodes.find((node) => node.id === draggingNodeId);
		if (!movingNode) return;
		if (movingNode.parent_id === targetParentId) {
			draggingNodeId = null;
			return;
		}

		if (targetParentId) {
			const targetParent = nodes.find((node) => node.id === targetParentId);
			if (!targetParent || targetParent.node_type !== 'directory') {
				draggingNodeId = null;
				return;
			}
			if (
				movingNode.node_type === 'directory' &&
				(targetParent.path === movingNode.path ||
					targetParent.path.startsWith(`${movingNode.path}/`))
			) {
				toast.error('Cannot move a folder into itself');
				draggingNodeId = null;
				return;
			}
		}

		try {
			await updateWorkspaceNode(token, ownerId, activeWorkspace.id, movingNode.id, {
				parent_id: targetParentId
			});
			await loadNodes();
			if (targetParentId && !expandedDirs.includes(targetParentId)) {
				expandedDirs = [...expandedDirs, targetParentId];
			}
		} catch (e: any) {
			toast.error(e?.message ?? 'Failed to move node');
		} finally {
			draggingNodeId = null;
		}
	}

	function toggleDir(id: string) {
		if (expandedDirs.includes(id)) {
			expandedDirs = expandedDirs.filter((d) => d !== id);
		} else {
			expandedDirs = [...expandedDirs, id];
		}
	}

	function openEditor(node: WorkspaceNode) {
		editingNodeId = node.id;
		editingContent = node.content;
	}

	function startRename(node: WorkspaceNode) {
		renameNodeId = node.id;
		renameValue = node.name;
	}

	function arrayBufferToBase64(buffer: ArrayBuffer): string {
		const bytes = new Uint8Array(buffer);
		const chunkSize = 0x8000;
		let binary = '';
		for (let i = 0; i < bytes.length; i += chunkSize) {
			binary += String.fromCharCode(...bytes.subarray(i, i + chunkSize));
		}
		return btoa(binary);
	}

	function isTextLikeFile(file: File): boolean {
		if (file.type.startsWith('text/')) return true;
		const textExtensions = new Set([
			'txt',
			'md',
			'json',
			'yaml',
			'yml',
			'xml',
			'csv',
			'tsv',
			'js',
			'ts',
			'jsx',
			'tsx',
			'py',
			'go',
			'java',
			'c',
			'cpp',
			'h',
			'hpp',
			'sh',
			'html',
			'css',
			'scss',
			'svelte',
			'sql',
			'log',
			'ini',
			'toml'
		]);
		const ext = file.name.split('.').pop()?.toLowerCase() ?? '';
		return textExtensions.has(ext);
	}

	async function readWorkspaceFileContent(file: File): Promise<string> {
		if (isTextLikeFile(file)) {
			return await file.text();
		}
		const buffer = await file.arrayBuffer();
		return `[binary file: ${file.name}, mime=${file.type || 'application/octet-stream'}, base64]\n${arrayBufferToBase64(buffer)}`;
	}

	async function ensureDirectoryPath(
		pathParts: string[],
		createdDirs: Map<string, string>
	): Promise<string | null> {
		if (!activeWorkspace || pathParts.length === 0) return null;

		let parentId: string | null = null;
		let currentPath = '';

		for (const rawPart of pathParts) {
			const part = rawPart.trim();
			if (!part) continue;
			currentPath = currentPath ? `${currentPath}/${part}` : part;

			const cachedId = createdDirs.get(currentPath);
			if (cachedId) {
				parentId = cachedId;
				continue;
			}

			const existing = nodes.find((n) => n.node_type === 'directory' && n.path === currentPath);
			if (existing) {
				createdDirs.set(currentPath, existing.id);
				parentId = existing.id;
				continue;
			}

			const created = await createWorkspaceNode(token, ownerId, activeWorkspace.id, {
				name: part,
				node_type: 'directory',
				parent_id: parentId
			});
			createdDirs.set(currentPath, created.id);
			parentId = created.id;
		}

		return parentId;
	}

	async function handleUploadFiles(fileList: FileList | null, preserveFolderPaths: boolean) {
		if (!activeWorkspace || !fileList?.length) return;
		isUploading = true;

		try {
			const files = Array.from(fileList);
			const createdDirs = new Map<string, string>();
			let createdOrUpdated = 0;

			for (const file of files) {
				const relativePath =
					preserveFolderPaths && file.webkitRelativePath
						? file.webkitRelativePath
						: file.name;

				const pathParts = relativePath.split('/').filter(Boolean);
				const fileName = pathParts.pop();
				if (!fileName) continue;

				const parentId = await ensureDirectoryPath(pathParts, createdDirs);
				const normalizedPath = [...pathParts, fileName].join('/');

				const existingFile = nodes.find(
					(n) => n.node_type === 'file' && n.path === normalizedPath
				);
				const content = await readWorkspaceFileContent(file);
				const mimeType = file.type || 'application/octet-stream';

				if (existingFile) {
					await updateWorkspaceNode(token, ownerId, activeWorkspace.id, existingFile.id, {
						content,
						mime_type: mimeType
					});
				} else {
					await createWorkspaceNode(token, ownerId, activeWorkspace.id, {
						name: fileName,
						node_type: 'file',
						parent_id: parentId,
						content,
						mime_type: mimeType
					});
				}

				createdOrUpdated += 1;
			}

			await loadNodes();
			toast.success(`${createdOrUpdated} file(s) uploaded`);
		} catch (e: any) {
			toast.error(e?.message ?? 'Failed to upload files');
		} finally {
			isUploading = false;
			if (fileInputEl) fileInputEl.value = '';
			if (folderInputEl) folderInputEl.value = '';
		}
	}

	function openFolderPicker() {
		if (!folderInputEl) return;
		const dirInput = folderInputEl as HTMLInputElement & {
			webkitdirectory?: boolean;
			directory?: boolean;
		};
		dirInput.webkitdirectory = true;
		dirInput.directory = true;
		folderInputEl.setAttribute('webkitdirectory', '');
		folderInputEl.setAttribute('directory', '');
		folderInputEl.click();
	}

	function triggerBlobDownload(blob: Blob, filename: string) {
		const objectUrl = URL.createObjectURL(blob);
		const anchor = document.createElement('a');
		anchor.href = objectUrl;
		anchor.download = filename;
		document.body.appendChild(anchor);
		anchor.click();
		anchor.remove();
		URL.revokeObjectURL(objectUrl);
	}

	async function handleDownloadWorkspace() {
		if (!activeWorkspace) return;
		isDownloadingWorkspace = true;
		try {
			const { blob, filename } = await downloadWorkspaceArchive(
				token,
				ownerId,
				activeWorkspace.id
			);
			triggerBlobDownload(blob, filename);
		} catch (e: any) {
			toast.error(e?.message ?? 'Failed to download workspace');
		} finally {
			isDownloadingWorkspace = false;
		}
	}

	async function handleDownloadFile(node: WorkspaceNode) {
		if (!activeWorkspace) return;
		try {
			const { blob, filename } = await downloadWorkspaceNode(
				token,
				ownerId,
				activeWorkspace.id,
				node.id
			);
			triggerBlobDownload(blob, filename);
		} catch (e: any) {
			toast.error(e?.message ?? 'Failed to download file');
		}
	}

	function detectLanguageFromFilename(filename: string): string {
		const ext = filename.split('.').pop()?.toLowerCase() ?? '';
		const map: Record<string, string> = {
			py: 'python',
			js: 'javascript',
			ts: 'typescript',
			jsx: 'jsx',
			tsx: 'tsx',
			json: 'json',
			md: 'markdown',
			html: 'html',
			css: 'css',
			scss: 'scss',
			yaml: 'yaml',
			yml: 'yaml',
			xml: 'xml',
			sh: 'shell',
			sql: 'sql',
			go: 'go',
			java: 'java',
			c: 'c',
			cpp: 'cpp',
			rs: 'rust',
			txt: 'text'
		};
		return map[ext] ?? 'text';
	}

	function resolveWorkspaceModelId(): string {
		const modelIds = ($models ?? []).map((model) => model.id);
		if (modelIds.includes('autoselect')) return 'autoselect';
		return modelIds[0] ?? 'autoselect';
	}

	function historyForAgent(maxMessages: number = 16) {
		return aiMessages
			.filter((message) => message.role === 'user' || message.role === 'assistant')
			.slice(-maxMessages)
			.map((message) => ({
				role: message.role as 'user' | 'assistant',
				content: message.content
			}));
	}

	function createWorkspaceAgentRunId(): string {
		if (typeof crypto !== 'undefined' && typeof crypto.randomUUID === 'function') {
			return crypto.randomUUID();
		}
		return `run-${Date.now()}-${Math.random().toString(16).slice(2)}`;
	}

	async function focusChangedFile(changedPaths: string[]) {
		if (!changedPaths.length) return;
		const changedSet = new Set(changedPaths);
		const changedFile = nodes.find(
			(node) => node.node_type === 'file' && changedSet.has(node.path)
		);
		if (changedFile) {
			openEditor(changedFile);
		}
	}

	async function sendWorkspaceAgentMessage() {
		if (!activeWorkspace || !aiInput.trim()) return;
		const prompt = aiInput.trim();
		if (
			!aiUseAutopilot &&
			/(^|\s)(напиши|сделай|создай|добавь|измени|реализуй|fix|implement|create|build|update)(\s|$)/i.test(
				prompt
			)
		) {
			toast.error('Для изменения файлов включи "Use autopilot (writes files)".');
			return;
		}
		const historyMessages = historyForAgent();
		const workspaceId = activeWorkspace.id;
		const runId = createWorkspaceAgentRunId();
		let statusPollTimer: ReturnType<typeof setInterval> | null = null;

		const userMessage: AIChatMessage = {
			id: crypto.randomUUID(),
			role: 'user',
			content: prompt
		};
		aiMessages = [...aiMessages, userMessage];

		aiInput = '';
		showAiOptions = false;
		aiLoading = true;
		aiLoadingStatus = 'Agent thinking...';

		const pollStage = async () => {
			try {
				const status = await getWorkspaceAgentStatus(token, ownerId, workspaceId, runId);
				const stage = String(status?.stage ?? '').trim();
				if (stage) {
					aiLoadingStatus = `Agent thinking: ${stage}`;
				}
			} catch {
				// Run status may not exist yet; ignore transient polling errors.
			}
		};
		statusPollTimer = setInterval(() => {
			void pollStage();
		}, 1200);
		void pollStage();

		try {
			const res = await runWorkspaceAgent(token, ownerId, workspaceId, {
				message: prompt,
				model: resolveWorkspaceModelId(),
				autopilot: aiUseAutopilot,
				history: historyMessages,
				run_id: runId
			});

			const text = String(res?.response ?? '').trim();
			if (!text) {
				toast.error('AI returned an empty response');
				return;
			}

			aiMessages = [
				...aiMessages,
				{
					id: crypto.randomUUID(),
					role: 'assistant',
					content: text
				}
			];

			if (aiUseAutopilot) {
				await loadNodes();
				const changedPaths = Array.isArray(res?.changed_paths)
					? (res.changed_paths as string[])
					: [];
				await focusChangedFile(changedPaths);
			}
		} catch (e: any) {
			toast.error(e?.message ?? 'Failed to run workspace AI');
		} finally {
			if (statusPollTimer) {
				clearInterval(statusPollTimer);
			}
			aiLoadingStatus = '';
			aiLoading = false;
		}
	}

	$: if (browser && activeWorkspace?.id) {
		persistWorkspaceChatHistory(activeWorkspace.id, aiMessages);
	}
</script>

<div class="flex h-full min-h-0 gap-0 overflow-hidden rounded-xl border border-gray-100 dark:border-gray-800 bg-white dark:bg-gray-900">
	{#if showWorkspaceList || !activeWorkspace}
		<!-- Sidebar: workspace list -->
		<div class="flex w-56 shrink-0 flex-col border-r border-gray-100 dark:border-gray-800 bg-gray-50 dark:bg-gray-900">
			<div class="flex items-center justify-between px-3 py-2 border-b border-gray-100 dark:border-gray-800">
				<span class="text-xs font-semibold uppercase tracking-wider text-gray-500 dark:text-gray-400">Workspaces</span>
				<button
					class="rounded p-0.5 hover:bg-gray-200 dark:hover:bg-gray-700 text-gray-500 dark:text-gray-400"
					title="New workspace"
					on:click={() => (showNewWorkspace = !showNewWorkspace)}
				>
					<svg xmlns="http://www.w3.org/2000/svg" class="h-3.5 w-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2">
						<path stroke-linecap="round" stroke-linejoin="round" d="M12 4v16m8-8H4" />
					</svg>
				</button>
			</div>

			{#if showNewWorkspace}
				<form
					class="flex gap-1 px-2 py-2 border-b border-gray-100 dark:border-gray-800"
					on:submit|preventDefault={handleCreateWorkspace}
				>
					<input
						class="flex-1 min-w-0 rounded border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 px-1.5 py-0.5 text-xs text-gray-800 dark:text-gray-100 focus:outline-none focus:ring-1 focus:ring-blue-500"
						bind:value={newWorkspaceName}
						placeholder="Name..."
						autofocus
					/>
					<button type="submit" class="rounded bg-blue-600 px-1.5 py-0.5 text-xs text-white hover:bg-blue-700">Add</button>
				</form>
			{/if}

			<div class="flex-1 overflow-y-auto py-1">
				{#each workspaces as ws (ws.id)}
					<div
						class="group flex items-center justify-between rounded mx-1 px-2 py-1.5 cursor-pointer text-sm {activeWorkspace?.id === ws.id ? 'bg-blue-50 dark:bg-blue-900/30 text-blue-700 dark:text-blue-300 font-medium' : 'text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-800'}"
						on:click={() => selectWorkspace(ws)}
						role="button"
						tabindex="0"
						on:keydown={(e) => e.key === 'Enter' && selectWorkspace(ws)}
					>
						<span class="truncate text-xs">{ws.name}</span>
						<button
							class="invisible group-hover:visible ml-1 rounded p-0.5 text-gray-400 hover:text-red-500"
							title="Delete workspace"
							on:click|stopPropagation={() => handleDeleteWorkspace(ws)}
						>
							<svg xmlns="http://www.w3.org/2000/svg" class="h-3 w-3" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2">
								<path stroke-linecap="round" stroke-linejoin="round" d="M6 18L18 6M6 6l12 12" />
							</svg>
						</button>
					</div>
				{/each}

				{#if workspaces.length === 0}
					<p class="px-3 py-4 text-xs text-center text-gray-400 dark:text-gray-500">No workspaces yet</p>
				{/if}
			</div>
		</div>
	{/if}

	<!-- File tree -->
	<div class="flex w-64 shrink-0 flex-col border-r border-gray-100 dark:border-gray-800">
		{#if activeWorkspace}
			<div class="flex items-center justify-between border-b border-gray-100 dark:border-gray-800 px-3 py-2">
				<div class="flex min-w-0 items-center gap-1">
					{#if !showWorkspaceList}
						<button
							class="rounded p-0.5 text-gray-500 hover:bg-gray-100 dark:hover:bg-gray-800 dark:text-gray-400"
							title="Back to workspaces"
							on:click={leaveWorkspace}
						>
							<svg xmlns="http://www.w3.org/2000/svg" class="h-3.5 w-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2">
								<path stroke-linecap="round" stroke-linejoin="round" d="M15 19l-7-7 7-7" />
							</svg>
						</button>
					{/if}
					<span class="truncate text-xs font-semibold text-gray-600 dark:text-gray-300">{activeWorkspace.name}</span>
				</div>
				<div class="flex items-center gap-1">
					<button
						class="rounded p-0.5 hover:bg-gray-100 dark:hover:bg-gray-800 text-gray-500 dark:text-gray-400"
						title="New file"
						on:click={() => handleCreateNode(null, 'file')}
					>
						<svg xmlns="http://www.w3.org/2000/svg" class="h-3.5 w-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2">
							<path stroke-linecap="round" stroke-linejoin="round" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414A1 1 0 0121 9.414V19a2 2 0 01-2 2z" />
						</svg>
					</button>
					<button
						class="rounded p-0.5 hover:bg-gray-100 dark:hover:bg-gray-800 text-gray-500 dark:text-gray-400"
						title="New folder"
						on:click={() => handleCreateNode(null, 'directory')}
					>
						<svg xmlns="http://www.w3.org/2000/svg" class="h-3.5 w-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2">
							<path stroke-linecap="round" stroke-linejoin="round" d="M3 7a2 2 0 012-2h4l2 2h8a2 2 0 012 2v8a2 2 0 01-2 2H5a2 2 0 01-2-2V7z" />
						</svg>
					</button>
					<button
						class="rounded p-0.5 hover:bg-gray-100 dark:hover:bg-gray-800 text-gray-500 dark:text-gray-400 disabled:opacity-50"
						title="Upload files"
						disabled={isUploading}
						on:click={() => fileInputEl?.click()}
					>
						<svg xmlns="http://www.w3.org/2000/svg" class="h-3.5 w-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2">
							<path stroke-linecap="round" stroke-linejoin="round" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4-4m0 0L8 12m4-4v12" />
						</svg>
					</button>
					<button
						class="rounded p-0.5 hover:bg-gray-100 dark:hover:bg-gray-800 text-gray-500 dark:text-gray-400 disabled:opacity-50"
						title="Upload folder"
						disabled={isUploading}
						on:click={openFolderPicker}
					>
						<svg xmlns="http://www.w3.org/2000/svg" class="h-3.5 w-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2">
							<path stroke-linecap="round" stroke-linejoin="round" d="M3 7a2 2 0 012-2h4l2 2h8a2 2 0 012 2v2m-9 4v-6m0 0l-3 3m3-3l3 3m-9 5h12a2 2 0 002-2v-1a2 2 0 00-2-2H5a2 2 0 00-2 2v1a2 2 0 002 2z" />
						</svg>
					</button>
					<button
						class="rounded p-0.5 hover:bg-gray-100 dark:hover:bg-gray-800 text-gray-500 dark:text-gray-400 disabled:opacity-50"
						title="Download workspace"
						disabled={isDownloadingWorkspace}
						on:click={handleDownloadWorkspace}
					>
						<svg xmlns="http://www.w3.org/2000/svg" class="h-3.5 w-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2">
							<path stroke-linecap="round" stroke-linejoin="round" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
						</svg>
					</button>
				</div>
			</div>
			{#if showCreateNodeForm}
				<form
					class="flex flex-col gap-1 px-2 py-2 border-b border-gray-100 dark:border-gray-800"
					on:submit|preventDefault={handleSubmitCreateNodeForm}
				>
					<div class="flex gap-1">
						<button
							type="button"
							class="rounded px-2 py-0.5 text-xs {createNodeType === 'file'
								? 'bg-blue-600 text-white'
								: 'bg-gray-100 text-gray-600 dark:bg-gray-800 dark:text-gray-300'}"
							on:click={() => (createNodeType = 'file')}
						>
							File
						</button>
						<button
							type="button"
							class="rounded px-2 py-0.5 text-xs {createNodeType === 'directory'
								? 'bg-blue-600 text-white'
								: 'bg-gray-100 text-gray-600 dark:bg-gray-800 dark:text-gray-300'}"
							on:click={() => (createNodeType = 'directory')}
						>
							Folder
						</button>
					</div>
					<div class="flex gap-1">
						<input
							class="flex-1 min-w-0 rounded border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 px-1.5 py-0.5 text-xs text-gray-800 dark:text-gray-100 focus:outline-none focus:ring-1 focus:ring-blue-500"
							bind:value={createNodeName}
							placeholder={createNodeType === 'file' ? 'File name...' : 'Folder name...'}
							autofocus
						/>
						<button type="submit" class="rounded bg-blue-600 px-1.5 py-0.5 text-xs text-white hover:bg-blue-700">Add</button>
						<button
							type="button"
							class="rounded px-1.5 py-0.5 text-xs text-gray-500 hover:text-gray-700 dark:hover:text-gray-300"
							on:click={() => {
								showCreateNodeForm = false;
								createNodeName = '';
								createNodeParentId = null;
							}}
						>
							Cancel
						</button>
					</div>
				</form>
			{/if}
			<input
				class="hidden"
				type="file"
				multiple
				bind:this={fileInputEl}
				on:change={(e) => handleUploadFiles(e.currentTarget.files, false)}
			/>
			<input
				class="hidden"
				type="file"
				multiple
				bind:this={folderInputEl}
				on:change={(e) => handleUploadFiles(e.currentTarget.files, true)}
			/>
			<div
				class="flex-1 overflow-y-auto py-1 text-xs"
				role="tree"
				aria-label="Workspace file tree"
				on:dragover={(e) => {
					e.preventDefault();
				}}
				on:drop={(e) => {
					e.preventDefault();
					void handleDropToParent(null);
				}}
			>
				{#each rootNodes as node (node.id)}
					<WorkspaceTreeNode
						{node}
						{nodes}
						{expandedDirs}
						{renameNodeId}
						{renameValue}
						{editingNodeId}
						depth={0}
						on:toggle={(e) => toggleDir(e.detail)}
						on:rename-start={(e) => startRename(e.detail)}
						on:rename-input={(e) => (renameValue = e.detail)}
						on:rename-commit={(e) => handleRenameNode(e.detail)}
						on:delete={(e) => handleDeleteNode(e.detail)}
						on:open-editor={(e) => openEditor(e.detail)}
						on:create-file={(e) => handleCreateNode(e.detail, 'file')}
						on:create-dir={(e) => handleCreateNode(e.detail, 'directory')}
						on:drag-start={(e) => handleDragStart(e.detail)}
						on:drag-end={handleDragEnd}
						on:drop-on-dir={(e) => {
							void handleDropToParent(e.detail);
						}}
					/>
				{/each}
				{#if nodes.length === 0}
					<p class="px-3 py-4 text-center text-gray-400 dark:text-gray-500">Empty workspace</p>
				{/if}
			</div>
		{:else}
			<div class="flex flex-1 items-center justify-center p-4 text-xs text-gray-400 dark:text-gray-500">
				Select a workspace
			</div>
		{/if}
	</div>

	<!-- Editor pane -->
	<div class="flex flex-1 flex-col min-w-0">
		<div class="flex flex-1 min-h-0">
			<div class="flex flex-1 min-w-0 flex-col border-r border-gray-100 dark:border-gray-800">
				{#if editingNodeId}
					{@const editNode = nodes.find((n) => n.id === editingNodeId)}
					{#if editNode}
						<div class="flex items-center justify-between border-b border-gray-100 dark:border-gray-800 px-4 py-2">
							<span class="truncate text-sm font-medium text-gray-700 dark:text-gray-200">{editNode.path}</span>
							<div class="flex items-center gap-2">
								<button
									class="rounded border border-gray-200 dark:border-gray-700 px-2 py-1 text-xs text-gray-600 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-800"
									on:click={() => handleDownloadFile(editNode)}
								>
									Download
								</button>
								<button
									class="rounded bg-blue-600 px-3 py-1 text-xs text-white hover:bg-blue-700"
									on:click={() => editNode && handleSaveContent(editNode)}
								>Save</button>
								<button
									class="rounded px-2 py-1 text-xs text-gray-500 hover:text-gray-700 dark:hover:text-gray-300"
									on:click={() => (editingNodeId = null)}
								>Close</button>
							</div>
						</div>
						<div class="flex-1 min-h-0">
							<CodeEditor
								id="workspace-file-editor"
								value={editingContent}
								lang={detectLanguageFromFilename(editNode.name)}
								onChange={(value) => {
									editingContent = value;
								}}
								onSave={() => editNode && handleSaveContent(editNode)}
							/>
						</div>
					{/if}
				{:else}
					<div class="flex flex-1 items-center justify-center text-sm text-gray-400 dark:text-gray-500">
						Select a file to edit
					</div>
				{/if}
			</div>

			<div class="flex w-[360px] shrink-0 flex-col">
				<div class="border-b border-gray-100 dark:border-gray-800 px-3 py-2">
					<div class="text-xs font-semibold text-gray-600 dark:text-gray-300">Workspace Agent</div>
				</div>

				<div class="flex-1 overflow-y-auto p-3 space-y-2">
					{#if aiMessages.length === 0}
						<div class="text-xs text-gray-400 dark:text-gray-500">
							Напиши задачу агенту по текущему workspace.
						</div>
					{/if}

					{#each aiMessages as message (message.id)}
						<div class="w-full {message.role === 'user' ? 'text-right' : ''}">
							{#if message.role === 'assistant'}
								<div class="inline-block max-w-[95%] rounded-lg bg-gray-100 dark:bg-gray-800 px-2.5 py-2 text-gray-700 dark:text-gray-200 text-xs text-left">
									<Markdown id={`workspace-agent-${message.id}`} content={message.content} done={true} />
								</div>
							{:else}
								<div class="inline-block max-w-[95%] rounded-lg px-2.5 py-2 text-xs whitespace-pre-wrap bg-blue-600 text-white">
									{message.content}
								</div>
							{/if}
						</div>
					{/each}

					{#if aiLoading}
						<div class="text-xs text-gray-500">{aiLoadingStatus || 'Agent is thinking...'}</div>
					{/if}
				</div>

				<div class="border-t border-gray-100 dark:border-gray-800 p-2.5">
					<div class="flex items-end gap-2">
						<textarea
							class="h-[122px] w-[265px] shrink-0 resize-none overflow-y-auto rounded border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 px-2 py-1.5 text-xs text-gray-800 dark:text-gray-100 outline-none"
							placeholder="Напиши задачу агенту..."
							bind:value={aiInput}
							on:keydown={(e) => {
								if (e.key === 'Enter' && !e.shiftKey) {
									e.preventDefault();
									void sendWorkspaceAgentMessage();
								}
							}}
						></textarea>

						<div class="relative flex items-center gap-1">
							<button
								class="rounded border border-gray-300 bg-gray-100 p-1 text-gray-700 hover:bg-gray-200 dark:border-gray-600 dark:bg-gray-700 dark:text-gray-100 dark:hover:bg-gray-600"
								title="Agent options"
								on:click={() => (showAiOptions = !showAiOptions)}
							>
								<svg xmlns="http://www.w3.org/2000/svg" class="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2">
									<path stroke-linecap="round" stroke-linejoin="round" d="M12 6h.01M12 12h.01M12 18h.01" />
								</svg>
							</button>
							{#if showAiOptions}
								<div class="absolute bottom-9 right-0 z-10 rounded-lg border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-900 p-2 shadow-lg">
									<label class="flex items-center gap-2 text-xs text-gray-600 dark:text-gray-300 whitespace-nowrap">
										<input type="checkbox" bind:checked={aiUseAutopilot} />
										Use autopilot (writes files)
									</label>
								</div>
							{/if}

							<button
								class="rounded bg-blue-600 p-2 text-white hover:bg-blue-700 disabled:opacity-50"
								aria-label="Send message"
								title="Send"
								disabled={aiLoading || !aiInput.trim()}
								on:click={() => void sendWorkspaceAgentMessage()}
							>
								<svg xmlns="http://www.w3.org/2000/svg" class="h-3.5 w-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2">
									<path stroke-linecap="round" stroke-linejoin="round" d="M5 12h14M13 6l6 6-6 6" />
								</svg>
							</button>
						</div>
					</div>
				</div>
			</div>
		</div>
	</div>
</div>
